sql:
SELECT a.species_name, i.island_name
FROM anole_species AS a
JOIN islands AS i ON a.island_id = i.island_id;

SELECT DISTINCT i.location
FROM islands i
JOIN anole_species a ON i.island_id = a.island_id;

SELECT COUNT(species_id) 
FROM anole_species 
WHERE habitat = 'tropical forest';

SELECT ecomorph_name, description
FROM ecomorphs
WHERE ecomorph_name = 'TW';

SELECT genus, species_name
FROM anole_species
WHERE genus = 'Anolis' AND species_name LIKE '%cubensis%';

external_knowledge:
- 'TW' refers to tree dwellers; 
- 'Hispaniola Ecomorphs Data' is the name of the dataset that contains information about lizard species found on the island of Hispaniola; 
- The measurements used are indicative of the lizard's adaptation to its arboreal lifestyle.

sql:
SELECT species_id, svl
FROM morphological_measurements
WHERE awesomeness > (
  SELECT AVG(awesomeness)
  FROM morphological_measurements
);

external_knowledge:
- 'Anole lizard species' are referred to metaphorically as 'mythical creatures'.;
- 'Island' is referred to metaphorically as 'enchanted isle'.;
- 'Location' is metaphorically described as 'magical land’s location in the mystical realm'.;
- 'Island_id = 1' represents a specific island that is of interest.;
